#!/usr/bin/env python3
"""Modern climate data analysis script."""

from __future__ import annotations

import configparser
from pathlib import Path

import pandas as pd


BASE_DIR = Path(__file__).resolve().parent
CONFIG_PATH = BASE_DIR / "climate_analyzer" / "config.ini"
DATA_PATH = BASE_DIR / "climate_analyzer" / "sample_data" / "climate_data.csv"


def read_config(config_path: Path = CONFIG_PATH) -> configparser.ConfigParser:
    """Read the legacy config with modern Python's configparser."""
    config = configparser.ConfigParser()
    config.read(config_path, encoding="utf-8")
    return config


def load_temperature_data(csv_path: Path = DATA_PATH) -> pd.DataFrame:
    """Load climate observations from a UTF-8 CSV file."""
    return pd.read_csv(
        csv_path,
        encoding="utf-8",
        parse_dates=["date"],
    )


def station_mean_temperatures(data: pd.DataFrame) -> pd.Series:
    """Return mean temperatures indexed by station id."""
    required_columns = {"station_id", "temperature"}
    missing_columns = required_columns.difference(data.columns)
    if missing_columns:
        missing = ", ".join(sorted(missing_columns))
        raise ValueError(f"Missing required column(s): {missing}")

    return data.groupby("station_id", sort=True)["temperature"].mean()


def main() -> None:
    read_config()
    data = load_temperature_data()

    for station_id, mean_temperature in station_mean_temperatures(data).items():
        print(f"Station {station_id} mean temperature: {mean_temperature:.1f}°C")


if __name__ == "__main__":
    main()
